INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('eldoria-rising', 'Eldoria Rising', 'Northwind Studios', 'Aurora Interactive', 2025, 94, 9.1, '["RPG","Adventure"]', '["PC","PS5","Xbox"]', 'https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1538481199705-c710c4e965fc?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1511512578047-dfb367046420?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1538481199705-c710c4e965fc?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1493711662062-fa541adb3fc8?auto=format&fit=crop&w=1200&h=800&q=80"]', 'An open-world fantasy epic with dynamic kingdoms.', 'Eldoria Rising weaves a sprawling, hand-crafted continent with reactive kingdoms, deep companion arcs, and a magic system built around elemental harmonies. Forge alliances, topple empires, or live as a bard chasing the perfect song.', 1, 1);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('neon-protocol', 'Neon Protocol', 'Vector Foundry', 'Pulse Games', 2025, 91, 8.8, '["Shooter","Action"]', '["PC","PS5","Xbox"]', 'https://images.unsplash.com/photo-1542751110-97427bbecf20?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1518709268805-4e9042af2176?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1542751110-97427bbecf20?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1518709268805-4e9042af2176?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1551103782-8ab07afd45c1?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Cyberpunk tactical shooter with mod-deep gunplay.', 'Neon Protocol drops you into a fractured megacity where every weapon, augment, and squadmate can be tuned mid-mission. The campaign branches based on which factions you burn — and which you build.', 0, 1);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('starforge-odyssey', 'Starforge Odyssey', 'Helios Labs', 'Helios Labs', 2024, 88, 8.4, '["RPG","Adventure","Simulation"]', '["PC","PS5"]', 'https://images.unsplash.com/photo-1462331940025-496dfbfc7564?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1419242902214-272b3f66ee7a?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1462331940025-496dfbfc7564?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1419242902214-272b3f66ee7a?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1517976487492-5750f3195933?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Build a fleet, chart the unknown, rewrite history.', 'Starforge Odyssey blends procedurally generated star systems with hand-authored story arcs. Manage a crew, customize ships down to the bulkheads, and uncover what really happened to the lost colonies.', 1, 1);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('ironhold', 'Ironhold', 'Boulder Bay', 'Anvil Press', 2024, 85, 8.6, '["Strategy","Simulation"]', '["PC"]', 'https://images.unsplash.com/photo-1591491653056-4e0f9c2a0c87?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1591491653056-4e0f9c2a0c87?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Colony-builder where every dwarf has a grudge.', 'Ironhold simulates an entire mountain civilization. Memories, feuds, masterworks and tragedies emerge from systems that never stop ticking, even when you''re not watching.', 0, 0);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('valor-arena', 'Valor Arena', 'Crimson Forge', 'Crimson Forge', 2024, 87, 8, '["Shooter","Action"]', '["PC","PS5","Xbox"]', 'https://images.unsplash.com/photo-1552820728-8b83bb6b773f?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1542751110-97427bbecf20?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1552820728-8b83bb6b773f?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1542751110-97427bbecf20?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Tactical 5v5 with a roster of agents and strict economy.', 'Valor Arena is the competitive backbone of the new tactical shooter scene — sharp gunplay, deep agent kits, and a tournament circuit watched by millions every weekend.', 1, 0);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('cobalt-circuit', 'Cobalt Circuit', 'Apex Drift', 'Octane Games', 2025, 89, 8.9, '["Racing","Sports"]', '["PC","PS5","Xbox"]', 'https://images.unsplash.com/photo-1503376780353-7e6692767b70?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1492144534655-ae79c964c9d7?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1503376780353-7e6692767b70?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1492144534655-ae79c964c9d7?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Open-world racing with a living motorsport calendar.', 'Cobalt Circuit treats motorsport like an MMO — qualifying weeks, rivalries, sponsor reputation, and a dynamic weather model that can ruin a finals lap in three seconds.', 0, 1);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('hollow-tides', 'Hollow Tides', 'Driftwood Collective', 'Indie Press Forge', 2024, 92, 9.3, '["Indie","Adventure"]', '["PC","Switch","PS5"]', 'https://images.unsplash.com/photo-1517816743773-6e0fd518b4a6?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1502082553048-f009c37129b9?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1517816743773-6e0fd518b4a6?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1502082553048-f009c37129b9?auto=format&fit=crop&w=1200&h=800&q=80"]', 'A painterly meditation on grief and the sea.', 'Hollow Tides is a short, deeply personal voyage. You inherit a lighthouse and the ghost of a town. Every chapter peels back another layer of what was lost — and what can still be saved.', 1, 0);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('rune-of-ash', 'Rune of Ash', 'Ember Tale', 'Aurora Interactive', 2023, 90, 9, '["RPG","Action"]', '["PC","PS5","Xbox","Switch"]', 'https://images.unsplash.com/photo-1559717865-a99cac1c95d8?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1559717865-a99cac1c95d8?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Soulslike with a twist: every death rewrites the world.', 'Rune of Ash reshuffles its own geography each time you fall. Master the loop, learn the bosses, and unlock endings hidden behind perma-deaths only the most ruthless players will ever see.', 0, 0);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('midnight-patrol', 'Midnight Patrol', 'Beacon House', 'Beacon House', 2025, 83, 8.2, '["Horror","Adventure"]', '["PC","PS5"]', 'https://images.unsplash.com/photo-1509198397868-475647b2a1e5?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1518709268805-4e9042af2176?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1509198397868-475647b2a1e5?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1518709268805-4e9042af2176?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Co-op horror set across decaying suburban America.', 'Midnight Patrol is built around two-player tension. One drives, one investigates. The radio knows things you don''t, and the route home is never the one you took out.', 0, 0);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('skybound-tactics', 'Skybound Tactics', 'Brigade Eleven', 'Pulse Games', 2024, 86, 8.5, '["Strategy","RPG"]', '["PC","Switch"]', 'https://images.unsplash.com/photo-1531297484001-80022131f5a1?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1493711662062-fa541adb3fc8?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1531297484001-80022131f5a1?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1493711662062-fa541adb3fc8?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Airship-era turn-based tactics with permadeath squads.', 'Skybound Tactics demands precision. Squads of six, hand-built officers with branching skill trees, and a campaign that punishes momentum more than mistakes.', 0, 0);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('afterlight', 'Afterlight', 'Lantern North', 'Aurora Interactive', 2025, 95, 9.4, '["Adventure","RPG"]', '["PC","PS5","Xbox"]', 'https://images.unsplash.com/photo-1502082553048-f009c37129b9?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1493711662062-fa541adb3fc8?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1502082553048-f009c37129b9?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1493711662062-fa541adb3fc8?auto=format&fit=crop&w=1200&h=800&q=80"]', 'The most acclaimed narrative game of the year.', 'Afterlight reimagines the linear adventure. Every chapter is a different photographer documenting the same impossible day. The truth depends on who''s holding the camera.', 1, 1);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('atlas-online', 'Atlas Online', 'Polaris Worlds', 'Polaris Worlds', 2023, 84, 8, '["MMO","RPG"]', '["PC"]', 'https://images.unsplash.com/photo-1511512578047-dfb367046420?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1511512578047-dfb367046420?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&w=1200&h=800&q=80"]', 'MMO with player-run economies and seasonal continents.', 'Atlas Online resets a continent every season. Guilds compete to shape laws, currency, and lore that carries forward — even as the map itself disappears.', 0, 0);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('pixel-pioneers', 'Pixel Pioneers', 'Tiny Forge', 'Tiny Forge', 2024, 82, 8.7, '["Indie","Simulation"]', '["PC","Switch"]', 'https://images.unsplash.com/photo-1493711662062-fa541adb3fc8?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1517816743773-6e0fd518b4a6?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1493711662062-fa541adb3fc8?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1517816743773-6e0fd518b4a6?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Cozy pixel-art town builder with a haunted twist.', 'Pixel Pioneers looks cozy on the box. Beneath the wholesome aesthetic is a sharp resource sim where every neighbor is keeping a secret you''ll eventually have to choose to bury or expose.', 0, 0);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('ironclad-cup', 'Ironclad Cup', 'Studio Goalpost', 'Studio Goalpost', 2024, 81, 7.8, '["Sports"]', '["PC","PS5","Xbox"]', 'https://images.unsplash.com/photo-1551698618-1dfe5d97d256?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1431324155629-1a6deb1dec8d?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1551698618-1dfe5d97d256?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1431324155629-1a6deb1dec8d?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Gritty football sim that finally fixes career mode.', 'Ironclad Cup throws out the cosmetic career mode and replaces it with negotiations, board pressure, fan sentiment, and a youth academy that actually matters.', 0, 0);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('ghost-stack', 'Ghost Stack', 'Outer Margin', 'Pulse Games', 2025, 88, 8.6, '["Action","Indie"]', '["PC","Switch","PS5"]', 'https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1559717865-a99cac1c95d8?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&w=1200&h=800&q=80","https://images.unsplash.com/photo-1559717865-a99cac1c95d8?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Fast-as-thought parkour shooter with rewind mechanics.', 'Ghost Stack is built around rewind. Die, watch the replay, then jump back into the same firefight with everything you just learned. Speedrunners have already reshaped its meta.', 0, 0);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('siege-of-volenta', 'Siege of Volenta', 'Black Banner Games', 'Black Banner Games', 2025, 89, 8.7, '["Strategy","Action"]', '["PC","PS5","Xbox"]', 'https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1493711662062-fa541adb3fc8?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Massive medieval sieges with full destructible castles.', 'Siege of Volenta lets two hundred players assault a single stronghold at once. Walls crumble, throne rooms burn, and history gets written one breach at a time.', 0, 0);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('kazoku-fighters', 'Kazoku Fighters', 'Iron Glove', 'Iron Glove', 2024, 90, 8.9, '["Fighting"]', '["PC","PS5","Xbox"]', 'https://images.unsplash.com/photo-1511512578047-dfb367046420?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1542751110-97427bbecf20?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1511512578047-dfb367046420?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Tag-team fighter built for tournament play.', 'Kazoku Fighters resurrected the tag-team subgenre. Rollback netcode, a 28-character launch roster, and a tournament scene that''s already produced two unforgettable grand finals.', 0, 0);
INSERT OR IGNORE INTO games (slug, title, developer, publisher, release_year, rating, user_score, genres, platforms, cover, hero, screenshots, short_description, description, trending, featured) VALUES ('harvest-orbit', 'Harvest Orbit', 'Greenfield Lab', 'Greenfield Lab', 2024, 85, 9, '["Simulation","Indie"]', '["PC","Switch","PS5"]', 'https://images.unsplash.com/photo-1419242902214-272b3f66ee7a?auto=format&fit=crop&w=1200&h=800&q=80', 'https://images.unsplash.com/photo-1462331940025-496dfbfc7564?auto=format&fit=crop&w=1920&h=900&q=80', '["https://images.unsplash.com/photo-1419242902214-272b3f66ee7a?auto=format&fit=crop&w=1200&h=800&q=80"]', 'Cozy farming on a tiny moon.', 'Harvest Orbit takes the farm sim into low gravity. Engineer hydroponics, befriend a research crew, and slowly turn a research outpost into a thriving little town that ships its produce home.', 0, 0);

INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('afterlight-game-of-the-year-frontrunner', 'Afterlight is the Game of the Year frontrunner — and it''s only April', 'Lantern North''s anthology adventure has redefined what a ''narrative game'' can be, and the awards conversation has already started.', '["It''s rare for a game to land in spring and dominate the Game of the Year conversation before E3 even happens. Afterlight has done exactly that.","Built around five photographers documenting the same impossible day, the game uses perspective as its core mechanic. Each chapter changes what you saw in the last one — sometimes by a degree, sometimes catastrophically.","Critics are already calling it the most confident debut from a major publisher in a decade. We sat down with creative director Mira Velez to talk about what comes next."]', 'IGN', 'Reviews', 'Jordan Kell', '2026-05-09T13:10:47.613Z', 'https://images.unsplash.com/photo-1493711662062-fa541adb3fc8?auto=format&fit=crop&w=1200&h=800&q=80', 'afterlight', 1, 184000, 'mock://afterlight-game-of-the-year-frontrunner');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('valor-arena-champions-bracket-set', 'Valor Arena Champions: full bracket revealed, Sentinel drawn into ''group of death''', 'The 16-team Champions bracket is locked. North America''s top seed faces the toughest path to the trophy.', '["Riot Forge''s Valor Arena Champions kicks off Friday with sixteen teams from five regions, a record-breaking $4M prize pool, and a bracket that has already broken several Discord servers.","Top seed Sentinel was drawn alongside reigning EU champions Iron Maple and Korean dark horse Black Lotus — a path the analyst desk is already calling unsurvivable.","Action begins Friday at 14:00 CET, broadcast in twelve languages."]', 'Dot Esports', 'Esports', 'Sami Ortega', '2026-05-09T11:10:47.614Z', 'https://images.unsplash.com/photo-1542751110-97427bbecf20?auto=format&fit=crop&w=1200&h=800&q=80', 'valor-arena', 1, 96400, 'mock://valor-arena-champions-bracket-set');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('neon-protocol-mod-tools', 'Vector Foundry confirms full mod tools for Neon Protocol this fall', 'After months of community pressure, the studio is shipping the same internal toolchain it used to build the campaign.', '["Vector Foundry confirmed Tuesday that Neon Protocol will receive a full mod SDK in October — including the campaign editor, AI behavior graphs, and weapon scripting tools used internally.","Studio head Kenta Iwasaki said the team had ''been building toward this since pre-production.''"]', 'PC Gamer', 'Updates', 'Reese Park', '2026-05-09T07:10:47.614Z', 'https://images.unsplash.com/photo-1518709268805-4e9042af2176?auto=format&fit=crop&w=1200&h=800&q=80', 'neon-protocol', 0, 41200, 'mock://neon-protocol-mod-tools');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('kazoku-fighters-rollback-patch', 'Kazoku Fighters'' new rollback patch is the smoothest fighter netcode of the year', 'Tournament organizers say the latest patch is finally tournament-ready for online qualifiers.', '["After three months of community testing, Iron Glove''s rollback overhaul has hit live servers — and the FGC is unanimously calling it a triumph.","Several upcoming majors have already announced they''ll allow online qualifiers using the new netcode, a first for the game."]', 'Polygon', 'Updates', 'Devon Maine', '2026-05-09T04:10:47.614Z', 'https://images.unsplash.com/photo-1511512578047-dfb367046420?auto=format&fit=crop&w=1200&h=800&q=80', 'kazoku-fighters', 0, 28900, 'mock://kazoku-fighters-rollback-patch');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('indie-publisher-layoffs', 'Mid-tier indie publisher Pulse Games confirms second round of layoffs', '30 staff affected as the publisher restructures around its live-service portfolio.', '["Pulse Games confirmed a second round of layoffs Wednesday, citing ''difficult market conditions'' and a strategic refocus on its live-service catalogue.","Around 30 staff are affected, with most cuts hitting the company''s narrative and external-relations teams."]', 'Eurogamer', 'Industry', 'Holly Brennan', '2026-05-09T01:10:47.614Z', 'https://images.unsplash.com/photo-1551103782-8ab07afd45c1?auto=format&fit=crop&w=1200&h=800&q=80', NULL, 0, 52800, 'mock://indie-publisher-layoffs');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('eldoria-rising-review', 'Eldoria Rising review: a fantasy RPG that finally trusts its players', 'Northwind Studios delivers the most ambitious open-world RPG since the genre''s last golden age.', '["Eldoria Rising is huge in a way modern open worlds rarely allow themselves to be.","Where most games of this scale corral you with quest markers and clean little arcs, Northwind has built something that lets you wander, get lost, fail upward, and stumble into stories no quest log will ever record."]', 'GameSpot', 'Reviews', 'Mira Tanaka', '2026-05-08T15:10:47.614Z', 'https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&w=1200&h=800&q=80', 'eldoria-rising', 1, 212300, 'mock://eldoria-rising-review');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('starforge-second-expansion', 'Starforge Odyssey''s second expansion arrives in June with full ship-to-ship boarding', 'Helios Labs goes deeper on the spacefaring sim with a feature fans have begged for.', '["Helios Labs unveiled the next major expansion for Starforge Odyssey at its summer showcase: ''Hollow Stars.''","The headline feature is full ship-to-ship boarding, plus a new faction whose entire economy is built around piracy."]', 'IGN', 'Updates', 'Casey Wren', '2026-05-08T15:10:47.614Z', 'https://images.unsplash.com/photo-1419242902214-272b3f66ee7a?auto=format&fit=crop&w=1200&h=800&q=80', 'starforge-odyssey', 0, 73200, 'mock://starforge-second-expansion');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('esports-league-relegation', 'League of Legends EU League relegates two storied orgs after disastrous split', 'Two of the league''s founding teams face a year out of the top tier.', '["After a brutal final week, the LEC has confirmed relegation for two of its founding orgs.","Both teams will play in the Challenger circuit next year, ending an unbroken decade in Europe''s top flight."]', 'Dot Esports', 'Esports', 'Linnea Holm', '2026-05-07T15:10:47.614Z', 'https://images.unsplash.com/photo-1552820728-8b83bb6b773f?auto=format&fit=crop&w=1200&h=800&q=80', NULL, 0, 64700, 'mock://esports-league-relegation');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('cs2-major-paris', 'CS2 Paris Major sells out in 11 minutes', 'All four days of the playoffs sold out faster than any major in the game''s history.', '["Tickets for the CS2 Paris Major sold out in 11 minutes flat this morning, the fastest the event has ever cleared.","Resale already shows finals tickets trading at over 8x face value."]', 'Dot Esports', 'Esports', 'Jules Marin', '2026-05-07T15:10:47.614Z', 'https://images.unsplash.com/photo-1542751110-97427bbecf20?auto=format&fit=crop&w=1200&h=800&q=80', NULL, 0, 88500, 'mock://cs2-major-paris');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('controversy-microtransactions', 'Backlash mounts as AAA shooter quietly reintroduces $25 cosmetic bundles', 'Players spotted the change in a 4GB patch this morning. The community is not pleased.', '["A weekend patch quietly reintroduced premium cosmetic bundles to one of last year''s biggest shooters.","Reaction across community channels has been overwhelmingly negative, with the official subreddit going private in protest."]', 'Kotaku', 'Drama', 'Sloane Park', '2026-05-06T15:10:47.614Z', 'https://images.unsplash.com/photo-1551103782-8ab07afd45c1?auto=format&fit=crop&w=1200&h=800&q=80', NULL, 0, 134200, 'mock://controversy-microtransactions');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('hollow-tides-soundtrack', 'Hollow Tides composer talks scoring grief without overscoring it', 'An interview with the BAFTA-winning composer behind the year''s most discussed indie.', '["Composer Saoirse Lin spent two years building the soundtrack to Hollow Tides — and she threw most of it away.","We talked to her about negative space, leaving the player room to feel, and the cello section that nearly didn''t make it in."]', 'Polygon', 'Reviews', 'Devon Maine', '2026-05-06T15:10:47.614Z', 'https://images.unsplash.com/photo-1517816743773-6e0fd518b4a6?auto=format&fit=crop&w=1200&h=800&q=80', 'hollow-tides', 0, 47800, 'mock://hollow-tides-soundtrack');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('next-gen-handheld-leak', 'Leaked benchmarks suggest a new handheld is targeting PS5-tier performance', 'Synthetic numbers point to a portable that punches well above its weight.', '["A trio of synthetic benchmark leaks this week has reignited speculation about an unannounced handheld targeting near-console performance in a portable form factor.","Industry analysts are split on whether the device is real, a dev kit, or a very elaborate fake."]', 'PC Gamer', 'Hardware', 'Reese Park', '2026-05-05T15:10:47.614Z', 'https://images.unsplash.com/photo-1531297484001-80022131f5a1?auto=format&fit=crop&w=1200&h=800&q=80', NULL, 0, 91600, 'mock://next-gen-handheld-leak');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('dota-international-host-city', 'The International returns to Seattle for its 15th anniversary', 'Valve confirms the marquee Dota 2 tournament will come home this October.', '["Valve confirmed today that The International 15 will be hosted in Seattle this October — a homecoming for the tournament''s anniversary.","The main event will be held at Climate Pledge Arena across four days."]', 'Dot Esports', 'Esports', 'Jules Marin', '2026-05-04T15:10:47.614Z', 'https://images.unsplash.com/photo-1493711662062-fa541adb3fc8?auto=format&fit=crop&w=1200&h=800&q=80', NULL, 0, 73900, 'mock://dota-international-host-city');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('midnight-patrol-co-op-update', 'Midnight Patrol''s free ''Long Way Home'' update doubles its map', 'Beacon House''s surprise expansion adds a new region and a four-player mode.', '["Beacon House surprise-dropped a free update for Midnight Patrol overnight, doubling the playable area and adding optional four-player support."]', 'Eurogamer', 'Updates', 'Holly Brennan', '2026-05-04T15:10:47.614Z', 'https://images.unsplash.com/photo-1509198397868-475647b2a1e5?auto=format&fit=crop&w=1200&h=800&q=80', 'midnight-patrol', 0, 33400, 'mock://midnight-patrol-co-op-update');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('studio-acquisition-aurora', 'Aurora Interactive acquires beloved indie studio in nine-figure deal', 'The publisher continues its aggressive acquisition spree.', '["Aurora Interactive has acquired indie darling Lantern North in a nine-figure deal that closed late Friday.","Lantern North''s leadership will remain in place, and the studio will operate independently within Aurora''s portfolio."]', 'IGN', 'Industry', 'Casey Wren', '2026-05-03T15:10:47.614Z', 'https://images.unsplash.com/photo-1559717865-a99cac1c95d8?auto=format&fit=crop&w=1200&h=800&q=80', NULL, 0, 105700, 'mock://studio-acquisition-aurora');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('valorant-agent-reveal', 'Valorant''s next agent leaked: a recon specialist with a deployable drone', 'Datamine reveals an unannounced agent''s full kit weeks before reveal.', '["Datamine reports surfaced over the weekend revealing what appears to be Valorant''s next agent — a recon specialist with a deployable drone.","Riot has not commented officially."]', 'Dot Esports', 'Esports', 'Sami Ortega', '2026-05-03T15:10:47.614Z', 'https://images.unsplash.com/photo-1542751110-97427bbecf20?auto=format&fit=crop&w=1200&h=800&q=80', NULL, 0, 88300, 'mock://valorant-agent-reveal');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('cobalt-circuit-tour-mode', 'Cobalt Circuit''s Tour mode is the racing career mode of the decade', 'Apex Drift''s living calendar makes every season feel personal.', '["Apex Drift''s Tour mode in Cobalt Circuit treats a racing career like an actual sport — with sponsor politics, mid-season negotiations, and rivalries that ripple across years."]', 'GameSpot', 'Reviews', 'Mira Tanaka', '2026-05-02T15:10:47.614Z', 'https://images.unsplash.com/photo-1503376780353-7e6692767b70?auto=format&fit=crop&w=1200&h=800&q=80', 'cobalt-circuit', 0, 41500, 'mock://cobalt-circuit-tour-mode');
INSERT OR IGNORE INTO articles (slug, title, excerpt, body, source, category, author, published_at, cover, related_game_slug, featured, reads, external_url) VALUES ('ironhold-mod-of-the-month', 'Ironhold''s modding scene is one of the strangest things on PC', 'From sentient dwarves to a working in-game stock market, the mods are wild.', '["Ironhold has one of the most committed modding communities on PC.","This month''s standout mod adds a working in-game stock market that fluctuates based on dwarf morale."]', 'PC Gamer', 'Updates', 'Reese Park', '2026-05-01T15:10:47.614Z', 'https://images.unsplash.com/photo-1591491653056-4e0f9c2a0c87?auto=format&fit=crop&w=1200&h=800&q=80', 'ironhold', 0, 22300, 'mock://ironhold-mod-of-the-month');

